SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND ((t.Volume_3M_P50*t.Price/ NULLIF(t.Inflation_7, 0))>1800000000.0) AND (t.Risk_Rating <= 5) AND (t.Close >1.08* t.Sup_1Y) AND (t.LO_3M_T1 < 0.99*t.Sup_1Y) AND ( t.Close < 1.49*t.LO_3M_T1) AND (t.PE < 18.5) AND (t.PE>2.0) AND (t.PB <1.35) AND (t.PB>0.34) AND (t.PCF <27.4) AND (t.PCF >0.2) AND ((t.Cash_P0/ (t.LtDebt_P0+1) > 0.005) OR ABS(t.IntCov_P0) > 8.8) AND ((t.CF_OA_5Y/ NULLIF(t.OShares, 0))> 4800.0) AND (t.ROE_Min5Y > 0.035) AND (CAST(t.ICB_Code AS STRING) != '2353') ORDER BY t.ticker, t.time